#pragma once

using vvi = std::vector<std::vector<int>>;


void gotoxy(int fila, int columna) {
	int nfila = fila + 1; //yo tomo como 0 0  la esquina pero el ansii la toma como  1 11 le sumo 1 pq no quiero reprogramar mi cerebro xd;
	int ncolumna = columna + 1; 
	std::cout << "\033[" << nfila << ";" << ncolumna << "H"; //codigo de escape ansi para esto;
	std::cout << std::flush;
}

void IniciarSesionFondo(int fila, int columna, int indiceIniciarSesionFondo) {
	gotoxy(fila + 0, columna); std::cout << std::flush;
	if (indiceIniciarSesionFondo == 1) { std::cout << "\033[38;2;255;255;0m"; }
	else { std::cout << "\033[38;2;146;208;80m"; }// verde spotify 
	std::cout << "Iniciar sesion";
	std::cout << "\033[0m";
	gotoxy(fila + 1, columna); std::cout << std::flush;
	if (indiceIniciarSesionFondo == 2) { std::cout << "\033[38;2;255;255;0m"; }
	else { std::cout << "\033[38;2;146;208;80m"; }// verde spotify 
	std::cout << "Agregar Usuario";
	std::cout << "\033[0m";
	gotoxy(fila + 2, columna); std::cout << std::flush;
	if (indiceIniciarSesionFondo == 3) { std::cout << "\033[38;2;255;255;0m"; }
	else { std::cout << "\033[38;2;146;208;80m"; }// verde spotify 
	std::cout << "Eliminar Usuario";
	std::cout << "\033[0m";
	gotoxy(fila + 3, columna); std::cout << std::flush;
	if (indiceIniciarSesionFondo == 4) { std::cout << "\033[38;2;255;255;0m"; }
	else { std::cout << "\033[38;2;146;208;80m"; }// verde spotify 
	std::cout << "Ver Canciones";
	std::cout << "\033[0m";
	gotoxy(fila + 4, columna); std::cout << std::flush;
	if (indiceIniciarSesionFondo == 5) { std::cout << "\033[38;2;255;255;0m"; }
	else { std::cout << "\033[38;2;146;208;80m"; }// verde spotify 
	std::cout << "Eliminar Canciones";
	std::cout << "\033[0m";
	gotoxy(fila + 5, columna); std::cout << std::flush;
	if (indiceIniciarSesionFondo == 6) { std::cout << "\033[38;2;255;255;0m"; }
	else { std::cout << "\033[38;2;146;208;80m"; }// verde spotify 
	std::cout << "Agregar Canciones";
	std::cout << "\033[0m";
}
